<?php
use App\Http\Controllers\Api\V1\AuthController; use App\Http\Controllers\Api\V1\CircleController; use App\Http\Controllers\Api\V1\MessageController; use App\Http\Controllers\Api\V1\NotificationController; use App\Http\Controllers\Api\V1\PollController; use Illuminate\Support\Facades\Route;
Route::prefix('v1')->group(function(){ Route::post('auth/login',[AuthController::class,'login'])->middleware('guest'); Route::middleware('auth:sanctum')->group(function(){ Route::post('auth/logout',[AuthController::class,'logout']); Route::get('me',[AuthController::class,'me']); Route::put('me/password',[AuthController::class,'changePassword']); Route::apiResource('circles',CircleController::class)->only(['index','store']); Route::get('circles/{circle}/messages',[MessageController::class,'index']); Route::post('circles/{circle}/messages',[MessageController::class,'store']); Route::get('poll',PollController::class); Route::get('notifications',[NotificationController::class,'index']); Route::post('notifications/{notification}/read',[NotificationController::class,'markRead']); }); });
